// Code node — Run Once for All Items
const body = $input.first().json.body;
const headers = $input.first().json.headers;

// Generate deduplication key
const dedupKey = `${body.service || 'unknown'}-${body.alert_name || 'unknown'}-${Math.floor(Date.now() / 60000)}`;

// Normalize severity hint (convert source-specific to internal)
const severityMap = {
  'p0': 'critical', 'p1': 'critical', 'p2': 'high',
  'p3': 'medium', 'p4': 'low', 'critical': 'critical',
  'high': 'high', 'warning': 'medium', 'info': 'low',
  'ok': 'low', '1': 'critical', '2': 'high', '3': 'medium', '4': 'low'
};

const rawSeverity = (body.severity_hint || body.severity || 'unknown').toLowerCase();
const normalizedSeverityHint = severityMap[rawSeverity] || 'medium';

// Sanitize logs (truncate to 2000 chars to stay within token limits)
const rawLogs = body.logs || body.message || body.description || 'No logs provided';
const truncatedLogs = rawLogs.length > 2000 ? rawLogs.substring(0, 2000) + '...[truncated]' : rawLogs;

const normalized = {
  // Core identification
  incident_id: `INC-${Date.now()}`,
  dedup_key: dedupKey,

  // Alert details
  alert_name: body.alert_name || body.alertname || body.title || 'Unknown Alert',
  service: body.service || body.labels?.service || body.tags?.service || 'unknown-service',
  environment: body.environment || body.env || body.labels?.environment || 'unknown',
  host: body.host || body.hostname || body.labels?.instance || 'unknown-host',

  // Time
  timestamp: body.timestamp || body.startsAt || new Date().toISOString(),
  received_at: new Date().toISOString(),

  // Severity
  severity_hint: normalizedSeverityHint,

  // Logs and metrics
  logs: truncatedLogs,
  metrics: body.metrics || {},

  // Source
  source: body.source || headers['x-source'] || 'unknown',

  // Raw for debugging
  raw_payload: JSON.stringify(body).substring(0, 500)
};

return [{ json: normalized }];

const aiResponse = $input.first().json;
const previousData = $('Normalize Alert Data').first().json;

let aiResult;

try {
  // Extract the content string from OpenRouter response
  const rawContent = aiResponse.choices?.[0]?.message?.content || '';

  // Strip any accidental markdown code blocks
  const cleaned = rawContent
    .replace(/```json\n?/gi, '')
    .replace(/```\n?/gi, '')
    .trim();

  aiResult = JSON.parse(cleaned);

  // Validate required fields
  const validSeverities = ['LOW', 'MEDIUM', 'HIGH', 'CRITICAL'];
  if (!validSeverities.includes(aiResult.severity)) {
    throw new Error(`Invalid severity: ${aiResult.severity}`);
  }

} catch (err) {
  // FALLBACK: If AI fails or returns invalid JSON
  console.log('AI parse failed, using fallback. Error:', err.message);
  aiResult = {
    severity: 'MEDIUM',
    confidence: 0,
    root_cause: 'AI triage unavailable - manual review required',
    affected_services: [previousData.service],
    recommended_action: 'Manually investigate alert - AI classification failed',
    escalation_required: false,
    estimated_impact: 'Unknown - AI triage failed',
    triage_summary: `Alert received for ${previousData.service} but AI triage failed. Manual review needed.`,
    ai_failed: true
  };
}

// Build the complete incident object
const incident = {
  ...previousData,

  // AI Analysis
  ai_severity: aiResult.severity,
  ai_confidence: aiResult.confidence || 0,
  ai_root_cause: aiResult.root_cause,
  ai_affected_services: aiResult.affected_services || [previousData.service],
  ai_recommended_action: aiResult.recommended_action,
  ai_escalation_required: aiResult.escalation_required ?? (aiResult.severity === 'CRITICAL' || aiResult.severity === 'HIGH'),
  ai_estimated_impact: aiResult.estimated_impact,
  ai_triage_summary: aiResult.triage_summary,
  ai_failed: aiResult.ai_failed || false,

  // Routing field for Switch node
  severity_level: aiResult.severity,

  // Slack channel name (lowercase, no spaces, max 80 chars)
  slack_channel_name: `incident-${previousData.service.replace(/[^a-z0-9]/gi, '-').toLowerCase()}-${Date.now().toString().slice(-6)}`,

  // Jira labels
  jira_priority: { 'CRITICAL': 'Highest', 'HIGH': 'High', 'MEDIUM': 'Medium', 'LOW': 'Low' }[aiResult.severity] || 'Medium',
};

return [{ json: incident }];

